你正在 review 一个高吞吐文件代理服务的代码，发现了下面两个函数。第一个函数负责把磁盘文件通过 socket 发给客户端：

```c
/* 将磁盘文件通过 socket 发送给客户端 */
int send_file_to_client(int sock_fd, int file_fd, off_t offset, size_t size) {
    int pfd[2];
    if (pipe(pfd) < 0) return -1;

    ssize_t sent = 0;
    while (sent < (ssize_t)size) {
        /* 第一步：把文件内容搬进管道 */
        ssize_t n = splice(file_fd, &offset, pfd[1], NULL,
                           size - sent, SPLICE_F_MOVE | SPLICE_F_MORE);
        if (n <= 0) break;
        /* 第二步：把管道内容发到 socket */
        ssize_t w = splice(pfd[0], NULL, sock_fd, NULL,
                           n, SPLICE_F_MOVE | SPLICE_F_MORE);
        if (w <= 0) break;
        sent += w;
    }
    close(pfd[0]);
    close(pfd[1]);
    return (int)sent;
}
```

第二个函数负责把一路数据流同时转发给处理节点和日志文件：

```c
/* 将数据流同时转发给处理节点和日志文件，不消耗原始管道中的数据 */
int tee_stream(int src_pipe, int log_pipe, int log_fd, size_t len) {
    /* tee 把 src_pipe 的数据复制到 log_pipe，但不消费 src_pipe 里的数据 */
    ssize_t n = tee(src_pipe, log_pipe, len, 0);
    if (n > 0) {
        /* 再把 log_pipe 的内容写入日志文件 */
        splice(log_pipe, NULL, log_fd, NULL, n, SPLICE_F_MOVE);
    }
    return (int)n;
}
```

同事提议把 `send_file_to_client` 改成更直观的 `read`/`write` 方式：

```c
int send_file_naive(int sock_fd, int file_fd, off_t offset, size_t size) {
    char buf[65536];
    lseek(file_fd, offset, SEEK_SET);
    ssize_t n;
    while ((n = read(file_fd, buf, sizeof(buf))) > 0) {
        write(sock_fd, buf, n);
    }
    return 0;
}
```

两种写法功能上等价，但这位同事坚持认为 splice 版本「在高并发下完全不是一个量级」。请分析：这两段代码分别在做什么？为什么选择 splice 和 tee 而不是 read/write 的组合？`SPLICE_F_MOVE` 与 `SPLICE_F_MORE` 两个 flag 分别有什么作用？tee 和直接 read 再 write 到两个 fd 有什么本质区别？
